import type * as React from 'react';
export interface SharedScrollAreaProps {
    /**
     * 显示滚动条的时机，可选常驻或滚动时显示
     * @defaultValue `whenScrolling`
     */
    showScrollBars?: 'whenScrolling' | 'always';
}
/**
 * @public
 * 虚拟滚动容器的属性
 */
export interface VirtualScrollAreaProps extends React.ComponentPropsWithoutRef<'div'>, SharedScrollAreaProps {
    /**
     * 是否使用模拟滚动条（可实现不占位）
     * @defaultValue true
     */
    virtual: true;
}
/**
 * @public
 * 原生滚动容器的属性
 */
export interface NativeScrollAreaProps extends React.ComponentPropsWithoutRef<'div'>, SharedScrollAreaProps {
    /**
     * 垂直方向内容超出是否显示滚动条
     * @defaultValue true
     */
    scrollY?: boolean;
    /**
     * 水平方向内容超出是否显示滚动条
     * @defaultValue false
     */
    scrollX?: boolean;
    /**
     * 隐藏滚动条的时延
     * @defaultValue 1000
     */
    hideTimeout?: number;
    /**
     * 是否使用模拟滚动条（可实现不占位）
     * @defaultValue false
     */
    virtual?: false;
}
export type ScrollAreaProps = NativeScrollAreaProps | VirtualScrollAreaProps;
